fn find_duplicates(videos: HashMap<u32, Video>) {
    let mut phashes = Vec::new();
    for (video_id, video) in videos.clone() {
        for phash in video.phash {
            phashes.push(Phash { video_id: video_id, phash: phash, neighbors: HashSet::new() });
        }
    }

    let max_distance: u32 = 6;
    let mut curr_video_id: u32 = u32::MAX;
    // Use rayon to parallelize this
    phashes.par_iter().for_each(|query| {
        phashes.par_iter().for_each(|item| {
            if query.video_id == item.video_id {
                return;
            }

            let distance = (query.phash ^ item.phash).count_ones();
            if distance <= max_distance {
                query.neighbors.insert(item.video_id);
                item.neighbors.insert(query.video_id);
            }
        });
    }); 
}
```

We use `phashes.par_iter()` to get a parallel iterator over the phashes. We then call `for_each` on that to perform the neighbor finding in parallel. The rest of the logic remains the same.

This will use all available CPU cores to perform the neighbor finding in parallel, speeding up the function.
